        // We need to count i <= k such that:
        // 1. OR(nums[i...j]) = O
        // 2. All nums[l] for l in [i, j] are submasks of O. (This implies OR(nums[i...j]) is a submask of O, and since O is one of the elements, the OR must be O if the elements cover all bits of O).

        // Condition 2 (all nums[l] must be submasks of O=nums[k]) is the most restrictive.
        // If nums[l] is not a submask of nums[k], then OR(nums[i...j]) will have bits not in nums[k], so OR != nums[k].

        // We iterate over all k from 0 to j (potential target element)
        for (let k = 0; k <= j; k++) {
            const target_or = nums[k];

            // Find the maximum valid starting index i_max <= k such that:
            // 1. For all l in [i_max, j], nums[l] is a submask of target_or (nums[l] | target_or == target_or).
            // 2. The OR of nums[i_max...j] equals target_or.

